import { execution } from '@dynatrace-sdk/automation-utils';
import { problemsClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  // Build filter string
  let filters = [];

  if (input.status && input.status !== 'ALL') {
    filters.push(`status("${input.status}")`);
  }

  if (input.severityLevel) {
    filters.push(`severity("${input.severityLevel}")`);
  }

  const timeFrameMs = parseInt(input.timeFrameMinutes) * 60 * 1000;
  const sinceTime = Date.now() - timeFrameMs;

  let problemSelector = '';
  if (filters.length > 0) {
    problemSelector = filters.join(' AND ');
  }

  try {
    const problems = await problemsClient.listProblems({
      problemSelector: problemSelector,
      from: sinceTime
    });

    console.log(`Retrieved ${problems.problems.length} problems`);

    // Limit results
    const limited = problems.problems.slice(0, parseInt(input.maxProblems));

    return {
      totalCount: problems.problems.length,
      returnedCount: limited.length,
      problems: limited
    };
  } catch (error) {
    console.error('Error retrieving problems:', error);
    throw new Error(`Failed to retrieve problems: ${error}`);
  }
}
